var BASE = "data/meals";
if (!Directory.Exists(Path.Combine(BASE, "Ciqual")) || !Directory.Exists(Path.Combine(BASE, "RecipeML")))
    Console.WriteLine("Donnees absentes. Lancez d'abord : python download_meal_data.py --areas Ciqual RecipeML");
else
