for (int O=0; O<=9; O++) { if (O==S||O==E||O==N||O==D||O==M) continue;
for (int R=0; R<=9; R++) { if (R==S||R==E||R==N||R==D||R==M||R==O) continue;
for (int Y=0; Y<=9; Y++) { if (Y==S||Y==E||Y==N||Y==D||Y==M||Y==O||Y==R) continue;
    if (S>0 && M>0) {
