var s2 = ctx.MkSolver();
s2.Assert(ctx.MkEq(ctx.MkMul(xs, xs), ctx.MkReal(2)));   // xs^2 = 2
Status st2 = s2.Check();

Console.WriteLine($"« xs² = 2 » : {st2}");
if (st2 == Status.SATISFIABLE) {
    var w = s2.Model.Eval(xs, true);
    Console.WriteLine($"  xs = {w}");
